sp_widget.client_script:
api.controller = function($scope, $http, $location, $rootScope, spModal, spUtil, $interpolate, htmlToStringService) {
    //------------------------------------------------------------------------------------------------------------------------
    // COMPANY: DISCOVER TECHNOLOGIES
    // CUSTOMIZED BY: KARINA TORRES
    // RECURSIVE GRAPHICAL TREE FOR PROCESS INSTANCE
    // HELPUL LINKS: https://gojs.net/latest/intro/textblocks.html
    //------------------------------------------------------------------------------------------------------------------------
    // 2.5.21 | 09.08.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
    // 2.7.0 | 2021-06-25 | mmcc | STRY0102408 "Task Tree Manager" tool tip displays "Unicode Decimal Codes" when entering 
    //											some special characters in "instruction" or "Signature Instructions" field
    // 											Add a private function to convert HTML to a simple string
    //											Added missing semicolons, formatted code
    // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
    //											some special characters in "instruction" or "Signature Instructions" field
    // 											Remove private function to convert HTML to a simple string; use service instead
    //											Instructions and Signature Instructions need HTML converted to string before
    //											the call to substring with field.maxChars
    //------------------------------------------------------------------------------------------------------------------------

    //	Font Awesome css
    // STRY0109208 - Add Create Icon
    var font_awesome_plus_o = '\uf067';
    var font_awesome_calendar_o = '\uf073';
    var font_awesome_user_edit_o = '\uf4ff';
    var font_awesome_user_o = '\uf007';
    var font_awesome_pencil_square_o = '\uf044';
    var font_awesome_file_text_o = '\uf0f6';
    var font_awesome_id_card_o = '\uf2c3';

    var font_awesome_exclamation_triangle_o = '\uf071';

    var font_awesome_clock_o = '\uf017';
    var font_awesome_bell_o = '\uf0a2';
    //	  var icon_normal_stroke = "#000";
    var icon_normal_stroke = "white";
    var icon_hover_stroke = "#F00";
    var icon_warning_stroke = "#FF0";
    var toolTipBackgroundColor = '#FFFFFF'; // "#C5C5C5"
    var tooltipTextColor = '#3A3F51';
    // -------------------------------------------------------------------	

    var node_selected_border = '#ADD8E6';

    var node_status_ontime = '#37C1C3'; //success
    var node_status_warning = '#F6C716'; //warning
    var node_status_critical = '#E32921'; //danger


    var node_state_waiting_bg = '#6b6b6b';
    var node_state_waiting_text = 'white';
    var node_state_waiting_warning = '#F6C716'; //warning
    var node_state_waiting_hover = '#F00'; //hover

    var node_state_unassigned_bg = '#F6C716'; //warning
    var node_state_unassigned_text = '#434343';
    var node_state_unassigned_warning = '#000000'; //warning
    var node_state_unassigned_hover = '#F00'; //hover

    var node_state_assigned_bg = '#427A93';
    var node_state_assigned_text = 'white';
    var node_state_assigned_warning = '#000000'; //warning
    var node_state_assigned_hover = '#F00'; //hover

    var node_state_accepted_bg = '#A0D468';
    var node_state_accepted_text = '#434343';
    var node_state_accepted_warning = '#000000'; //warning
    var node_state_accepted_hover = '#2E3C54'; //hover

    var node_state_rejected_bg = '#E32921'; //danger 
    var node_state_rejected_text = 'white';
    var node_state_rejected_warning = '#000000'; //warning
    var node_state_rejected_hover = '#F5F5F5'; //hover

    var node_state_workinprogress_bg = '#2E3C54'; //primary
    var node_state_workinprogress_text = 'white';
    var node_state_workinprogress_warning = '#F6C716'; //warning
    var node_state_workinprogress_hover = '#F5F5F5'; //hover

    var node_state_workscheduled_bg = '#2E3C54'; //primary
    var node_state_workscheduled_text = 'white';
    var node_state_workscheduled_warning = '#F6C716'; //warning
    var node_state_workscheduled_hover = '#F5F5F5'; //hover

    var node_state_inreview_bg = '#736ac6'; //info
    var node_state_inreview_text = 'white';
    var node_state_inreview_warning = '#000000'; //warning
    var node_state_inreview_hover = '#F5F5F5'; //hover

    var node_state_rework_bg = '#2E3C54'; //primary
    var node_state_rework_text = 'white';
    var node_state_rework_warning = '#F6C716'; //warning
    var node_state_rework_hover = '#F5F5F5'; //hover

    var node_state_completed_bg = '#37C1C3'; //success
    var node_state_completed_text = '#434343';
    var node_state_completed_warning = '#000000'; //warning
    var node_state_completed_hover = '#2E3C54'; //hover

    var node_state_closedincomplete_bg = '#37C1C3'; //success
    var node_state_closedincomplete_text = '#434343';
    var node_state_closedincomplete_warning = '#000000'; //warning
    var node_state_closedincomplete_hover = '#2E3C54'; //hover

    var node_state_cancelled_bg = '#37C1C3'; //success
    var node_state_cancelled_text = '#434343';
    var node_state_cancelled_warning = '#000000'; //warning
    var node_state_cancelled_hover = '#2E3C54'; //hover

    var node_colors = {
        "waiting": {
            bg: '#6b6b6b',
            text: 'white',
            warning: '#F6C716',
            hover: '#F00'
        },
        "unassigned": {
            bg: '#F6C716',
            text: '#434343',
            warning: '#000000',
            hover: '#F00'
        },
        "assigned": {
            bg: '#427A93',
            text: 'white',
            warning: '#000000',
            hover: '#F00'
        },
        "accepted": {
            bg: '#A0D468',
            text: '#434343',
            warning: '#000000',
            hover: '#2E3C54'
        },
        "rejected": {
            bg: '#E32921',
            text: 'white',
            warning: '#000000',
            hover: '#F5F5F5'
        },
        "workinprogress": {
            bg: '#2E3C54',
            text: 'white',
            warning: '#F6C716',
            hover: '#F5F5F5'
        },
        "workscheduled": {
            bg: '#2E3C54',
            text: 'white',
            warning: '#F6C716',
            hover: '#F5F5F5'
        },
        "inreview": {
            bg: '#736ac6',
            text: 'white',
            warning: '#000000',
            hover: '#F5F5F5'
        },
        "rework": {
            bg: '#2E3C54',
            text: 'white',
            warning: '#F6C716',
            hover: '#F5F5F5'
        },
        "completed": {
            bg: '#37C1C3',
            text: '#434343',
            warning: '#000000',
            hover: '#2E3C54'
        },
        "closedincomplete": {
            bg: '#37C1C3',
            text: '#434343',
            warning: '#000000',
            hover: '#2E3C54'
        },
        "cancelled": {
            bg: '#37C1C3',
            text: '#434343',
            warning: '#000000',
            hover: '#2E3C54'
        },
        "colorDefault": {
            bg: '#6b6b6b',
            text: 'white',
            warning: '#F6C716',
            hover: '#F00'
        }
    };

    function getStateColors(state, type) {
        var font_color;
        switch (state) {
            case "-3": // waiting
                font_color = getFontColors(type, node_colors.waiting);
                break;
            case "-5": // unassigned
                font_color = getFontColors(type, node_colors.unassigned);
                break;
            case "1": // assigned
                font_color = getFontColors(type, node_colors.assigned);
                break;
            case "10": // accepted
                font_color = getFontColors(type, node_colors.accepted);
                break;
            case "11": // rejected
                font_color = getFontColors(type, node_colors.rejected);
                break;
            case "13": // workinprogress
                font_color = getFontColors(type, node_colors.workinprogress);
                break;
            case "12": // workscheduled
                font_color = getFontColors(type, node_colors.workscheduled);
                break;
            case "14": // inreview
                font_color = getFontColors(type, node_colors.inreview);
                break;
            case "15": // rework
                font_color = getFontColors(type, node_colors.rework);
                break;
            case "3": // completed
                font_color = getFontColors(type, node_colors.completed);
                break;
            case "4": // closedincomplete
                font_color = getFontColors(type, node_colors.closedincomplete);
                break;
            case "7": // cancelled
                font_color = getFontColors(type, node_colors.cancelled);
                break;
            default:
                font_color = getFontColors(type, node_colors.colorDefault);
        }
        return font_color;
    }

    function getFontColors(type, fontColors) {
        var font_color;
        switch (type) {
            case "bg":
                font_color = fontColors.bg;
                break;
            case "text":
                font_color = fontColors.text;
                break;
            case "warning":
                font_color = fontColors.warning;
                break;
            case "hover":
                font_color = fontColors.hover;
                break;
        }
        return font_color;
    }

    // STRY0072032
    var diagram;
    var c = this;

    // STRY0096156 - RJ - set Minimum Height for Tree
    var diagramMinHeight = 150;

    // 2.5.13: 08.12.20 | KT | SEQ | STRY0076601: SEQ - Task Details page – Displays Task Tree View Indicators 
    //if (grTask.assigned_to.getDisplayValue().toString().length > 0) nodeTitle += " (" + grTask.assigned_to.getDisplayValue().toString() + ") "; //KT: 06.09.20: Added space before (Assignee

    spUtil.recordWatch($scope, $scope.data.table, "u_task_tree=" + $scope.data.task_tree, function(name) {
        // STRY0099313 - Task Manager - When a Task is updated and the Task Tree Graph isn't loaded, ignore the update
        if (diagram != undefined) {
            var changes = name.data.changes;
            var sys_id = name.data.sys_id;
            switch (name.data.operation) {
                case "update":
                    var nodeChangedFound = diagram.model.findNodeDataForKey(sys_id);
                    if (nodeChangedFound) {
                        var nodeDataChanged = false;
                        for (var change in changes) {
                            if (c.data.fieldsInModel[changes[change]]) {
                                nodeDataChanged = true;
                                break;
                            }
                        }
                        if (nodeDataChanged) {
                            updateModelNodeData(nodeChangedFound, name.data.record);
                        }
                    }
                    break;
                case "insert":
					// 2.7.0 | 2021-11-02 | mmcc | DFCT0010588 - When creating a Subtask on the Task form, record watcher shows 2 subtasks created
					// .model.findNodeDataForKey() returns null if a node data with that key cannot be found in the model...
					var isNotFoundNodeInsert = diagram.model.findNodeDataForKey(sys_id) == null;
					if (isNotFoundNodeInsert) {
						if (name.data.record.parent) {
							var newNodeData = createModelNodeData(sys_id, name.data.record);
							diagram.startTransaction("Add new Task");
							diagram.model.addNodeData(newNodeData);
							diagram.model.setParentKeyForNodeData(newNodeData, name.data.record.parent.value);
							diagram.commitTransaction("Add new Task");
							// if suspensedate changed, need to check parent and all subtasks again
							checkDateWarnings(newNodeData);
						}
					}
                    break;
                case "delete":
                    var nodeDeletedFound = diagram.model.findNodeDataForKey(sys_id);
                    if (nodeDeletedFound) {
                        diagram.model.removeNodeData(nodeDeletedFound);
                    }
            }
        }
    });
    // load all of the field names used in the task tree nodes (see TaskHelpers.getTaskTreeLevelO and TaskHelpers.getTaskTitleNode)
    function createModelNodeData(sys_id, record) {
        var newNodeData = {};
        newNodeData.key = sys_id;
        newNodeData.sys_id = sys_id;
        for (var key in record) {
            var displayValue = '';
            var fieldLabel = '';
            var field = c.data.fieldsInModel[key];
            if (field) {
                fieldLabel = field.fieldLabel;

                // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode
                // displayValue = record[key].display_value;
                if ((field.fieldName == 'u_signature_instructions') || (field.fieldName == 'instructions')) {
                    displayValue = htmlToStringService.convertHtmlToString(record[key].display_value);
                } else {
                    displayValue = record[key].display_value;
                }

                if (field.maxChars > 0)
                    displayValue = displayValue.toString().length > field.maxChars ? displayValue.substring(0, field.maxChars - 1) : displayValue.toString();
                if (field.hasValue) {
                    // many have value, only a few have only value 'calchaschildren', 'parent', 'u_wait_for_subtasks_to_finish'
                    // others 'primary_assignee', 'primary_office', 'tasking_authority', 'state', 'assigned_to'
                    newNodeData[key] = record[key].value;
                }
                if (field.keyUsesDisplayOnly) {
                    // 'status', 'task_name', 'u_active_subtasks', 'order', 'u_reviewer': 
                    newNodeData[key] = displayValue;
                }
                if (field.hasDiplayValue) {
                    // 'state_DisplayValue', 'assigned_to_DisplayValue'
                    newNodeData[key + '_DisplayValue'] = displayValue;
                }
                if (field.type == 'date') {
                    var date_number = getDateFromFormat(record[key].value, g_user_date_time_format);
                    newNodeData[key] = date_number;
                }
            } //if field wasn't found do nothing
        }
        newNodeData.name = getTaskTitleNode(newNodeData);
        newNodeData.warning = {};

        // STRY0095748 - no suspensedate warning
        newNodeData.warning.noSuspenseDate = (newNodeData.suspense_date == '' || newNodeData.suspense_date == null);
        // New cannot be top in this context.  So, set to false on exteneral inbound fo task
        newNodeData.isInboundExternalOU = false;
        newNodeData.warning.isTopSuspenseDateAfterExternalInboundDate = false;
        newNodeData.isOutboundExternalOU = (record.outbound == true);
        newNodeData.warning.isTopSuspenseDateBeforeExternalOutboundDate = newNodeData.isOutboundExternalOU && (record.u_external_due_date > record.suspense_date);

        newNodeData.warning.waitStatewithNoSubtasks = (newNodeData.u_wait_for_subtasks_to_finish == 'true' && (parseInt(newNodeData.calchaschildren) == 0));
        newNodeData.warning.primaryAssigneeEmpty = (newNodeData.primary_assignee == '' || newNodeData.primary_assignee == null);
        newNodeData.warning.assignedMemberEmpty = ((newNodeData.assigned_to == '' || newNodeData.assigned_to == null));

        // if status is not provided on a new record, set to unkown
        if (!newNodeData.status)
            newNodeData.status = 'unkown';

        return newNodeData;
    }

    // load all of the field names used in the task tree nodes (see TaskHelpers.getTaskTreeLevelO and TaskHelpers.getTaskTitleNode)
    function updateModelNodeData(nodeData, record) {
        for (var key in record) {
            var displayValue = '';
            var fieldLabel = '';
            var field = c.data.fieldsInModel[key];
            if (field) {
                fieldLabel = field.fieldLabel;

                // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode
                // displayValue = record[key].display_value;
                if ((field.fieldName == 'u_signature_instructions') || (field.fieldName == 'instructions')) {
                    displayValue = htmlToStringService.convertHtmlToString(record[key].display_value);
                } else {
                    displayValue = record[key].display_value;
                }

                if (field.maxChars > 0)
                    displayValue = displayValue.toString().length > field.maxChars ? displayValue.substring(0, field.maxChars - 1) : displayValue.toString();
                if (field.hasValue) {
                    // many have value, only a few have only value 'calchaschildren', 'parent', 'u_wait_for_subtasks_to_finish'
                    // others 'primary_assignee', 'primary_office', 'tasking_authority', 'state', 'assigned_to'
                    diagram.model.setDataProperty(nodeData, key, record[key].value); // this is the default value to key match
                }
                if (field.keyUsesDisplayOnly) {
                    // 'status', 'task_name', 'u_active_subtasks', 'order', 'u_reviewer': 
                    diagram.model.setDataProperty(nodeData, key, displayValue);
                }
                if (field.hasDiplayValue) {
                    // 'state_DisplayValue', 'assigned_to_DisplayValue'
                    diagram.model.setDataProperty(nodeData, key + '_DisplayValue', displayValue);
                }
                if (field.type == 'date') {
                    var date_number = getDateFromFormat(record[key].value, g_user_date_time_format);
                    diagram.model.setDataProperty(nodeData, key, date_number);
                }
            } //if field wasn't found do nothing
        }
        var nameValue = getTaskTitleNode(nodeData);
        if (nodeData.name != nameValue) {
            diagram.model.setDataProperty(nodeData, 'name', nameValue);
        }
        var newWaitState = (nodeData.u_wait_for_subtasks_to_finish == 'true' && (parseInt(nodeData.calchaschildren) == 0));
        if (nodeData.warning.waitStatewithNoSubtasks != newWaitState) {
            diagram.model.setDataProperty(nodeData.warning, 'waitStatewithNoSubtasks', newWaitState);
        }
        // STRY0095748 - no suspensedate warning
        var newSuspenseDateFlag = (nodeData.suspense_date == '' || nodeData.suspense_date == null);
        if (nodeData.warning.noSuspenseDate != newSuspenseDateFlag) {
            diagram.model.setDataProperty(nodeData.warning, 'noSuspenseDate', newSuspenseDateFlag);
        }
        var newExtInboundFlag = nodeData.isInboundExternalOU && (nodeData.suspense_date > nodeData.u_external_due_date);
        if (nodeData.warning.isTopSuspenseDateAfterExternalInboundDate != newExtInboundFlag) {
            diagram.model.setDataProperty(nodeData.warning, 'isTopSuspenseDateAfterExternalInboundDate', newExtInboundFlag);
        }
        var newExtOutboundFlag = nodeData.isOutboundExternalOU && (nodeData.u_external_due_date > nodeData.suspense_date);
        if (nodeData.warning.isTopSuspenseDateBeforeExternalOutboundDate != newExtOutboundFlag) {
            diagram.model.setDataProperty(nodeData.warning, 'isTopSuspenseDateBeforeExternalOutboundDate', newExtOutboundFlag);
        }

        var primaryAssigneeEmpty = (nodeData.primary_assignee == '' || nodeData.primary_assignee == null);
        if (primaryAssigneeEmpty != nodeData.warning.primaryAssigneeEmpty) {
            diagram.model.setDataProperty(nodeData.warning, 'primaryAssigneeEmpty', primaryAssigneeEmpty);
        }
        var assignedMemberEmpty = ((nodeData.assigned_to == '' || nodeData.assigned_to == null));
        if (assignedMemberEmpty != nodeData.warning.assignedMemberEmpty) {
            diagram.model.setDataProperty(nodeData.warning, 'assignedMemberEmpty', assignedMemberEmpty);
        }
        // if suspensedate changed, need to check parent and all subtasks again
        checkDateWarnings(nodeData);
        diagram.model.updateTargetBindings(nodeData);
    }

    function getTaskTitleNode(nodeData) {
        var nodeTitle = nodeData.task_name;
        if (nodeData.parent != '') nodeTitle = nodeData.order + ". " + nodeTitle; // NEW
        switch (nodeData.state_DisplayValue) {
            case 'Waiting':
                if (nodeData.calchaschildren == '0')
                    nodeTitle += " - " + nodeData.state_DisplayValue + " on creating Subtasks ";
                else
                    nodeTitle += " - " + nodeData.state_DisplayValue + " on " + nodeData.u_active_subtasks + " out of " + nodeData.calchaschildren + " Subtasks";
                break;
            case 'Assigned':
            case 'Accepted':
                nodeTitle += " - " + nodeData.state_DisplayValue + " to " + nodeData.assigned_to_DisplayValue;
                break;
            case 'Work in Progress':
            case 'Completed':
                nodeTitle += " - " + nodeData.state_DisplayValue + " by " + nodeData.assigned_to_DisplayValue;
                break;
            case 'In Review':
                nodeTitle += " - " + nodeData.state_DisplayValue + " by " + nodeData.u_reviewer + ", Worked by " + nodeData.assigned_to_DisplayValue;
                break;
            default:
                nodeTitle += " - " + nodeData.state_DisplayValue;
                break;
        }
        return nodeTitle;
    }

    function checkDateWarnings(changedNodeData) {
        if (changedNodeData.parent != '' && changedNodeData.parent != undefined) {
            var parentNodeData = diagram.model.findNodeDataForKey(changedNodeData.parent);
            compareParentDateToAllChildren(parentNodeData.sys_id);
        }
        compareParentDateToAllChildren(changedNodeData.sys_id);
    }

    function compareParentDateToAllChildren(parentKey) {
        var parentNode = diagram.findNodeForKey(parentKey);
        var childrenNodes = parentNode.findTreeChildrenNodes();
        var parentAfterAllChildren = true;
        while (childrenNodes.next()) {
            var node = childrenNodes.value;
            var childAfterParent = (node.data.suspense_date > parentNode.data.suspense_date);
            if (childAfterParent) {
                parentAfterAllChildren = false;
            }
            diagram.model.setDataProperty(node.data.warning, 'isSuspenseDateAfterParent', childAfterParent);
            diagram.model.updateTargetBindings(node.data);
        }
        diagram.model.setDataProperty(parentNode.data.warning, 'isSuspenseDateAfterChildren', parentAfterAllChildren);
        diagram.model.updateTargetBindings(parentNode.data);
    }

    // STRY0091260
    function getToolTipText(objectName) {
        var $go = go.GraphObject.make; // for conciseness in defining templates
        var toolTip;
        switch (objectName) {
            // // STRY0109208 - Add Create Icon
            case 'AddIcon':
                toolTip = $go(go.Panel, "Table",
                    $go(go.TextBlock, c.data.createTaskTitle, {
                        row: 0,
                        column: 0,
                        alignment: go.Spot.Left,
                        margin: 2,
                        background: toolTipBackgroundColor
                    })
                );
                break;
            case 'DurationIcon':
                var durrationWarningCount = 1;
                toolTip = $go(go.Panel, "Table",
                    $go(go.TextBlock, c.data.fieldsInModel.suspense_date.fieldLabel + ": ", {
                        row: 0,
                        column: 0,
                        alignment: go.Spot.Right,
                        margin: 2,
                        background: toolTipBackgroundColor
                    }),
                    $go(go.TextBlock,
                        new go.Binding("text", "", function(data) {
                            return data.suspense_date_DisplayValue;
                        }), {
                            row: 0,
                            column: 1,
                            alignment: go.Spot.Left,
                            margin: 2,
                            background: toolTipBackgroundColor
                        }),
                    $go(go.TextBlock, c.data.durationWarningWaitState, {
                            visible: false,
                            row: 1,
                            column: 0,
                            columnSpan: 2,
                            alignment: go.Spot.Left,
                            margin: 5,
                            background: toolTipBackgroundColor
                        },
                        new go.Binding("visible", "", function(data) {
                            return (data.warning.waitStatewithNoSubtasks == true);
                        })),
                    // STRY0095748 
                    $go(go.TextBlock, c.data.durationWarningNoSuspenseDate, {
                            visible: false,
                            row: 2,
                            column: 0,
                            columnSpan: 2,
                            alignment: go.Spot.Left,
                            margin: 5,
                            background: toolTipBackgroundColor
                        },
                        new go.Binding("visible", "", function(data) {
                            return (data.warning.noSuspenseDate == true);
                        })),
                    $go(go.TextBlock, c.data.durationWarningInternalSuspenseDateAfterExternalDate, {
                            visible: false,
                            row: 3,
                            column: 0,
                            columnSpan: 2,
                            alignment: go.Spot.Left,
                            margin: 5,
                            background: toolTipBackgroundColor
                        },
                        new go.Binding("visible", "", function(data) {
                            return (data.warning.isTopSuspenseDateAfterExternalInboundDate == true);
                        })),
                    $go(go.TextBlock, c.data.durationWarningInternalSuspenseBeforeExternalDate, {
                            visible: false,
                            row: 4,
                            column: 0,
                            columnSpan: 2,
                            alignment: go.Spot.Left,
                            margin: 5,
                            background: toolTipBackgroundColor
                        },
                        new go.Binding("visible", "", function(data) {
                            return (data.warning.isTopSuspenseDateBeforeExternalOutboundDate == true);
                        })),
                    $go(go.TextBlock, c.data.durationWarningParent, {
                            visible: false,
                            row: 5,
                            column: 0,
                            columnSpan: 2,
                            alignment: go.Spot.Left,
                            margin: 5,
                            background: toolTipBackgroundColor,
                            width: 600,
                            wrap: go.TextBlock.WrapFit
                        },
                        new go.Binding("visible", "", function(data) {
                            return (data.warning.isSuspenseDateAfterChildren != true);
                        })),
                    $go(go.TextBlock, c.data.durationWarningSubTask, {
                            visible: false,
                            row: 6,
                            column: 0,
                            columnSpan: 2,
                            alignment: go.Spot.Left,
                            margin: 5,
                            background: toolTipBackgroundColor,
                            width: 600,
                            wrap: go.TextBlock.WrapFit
                        },
                        new go.Binding("visible", "", function(data) {
                            return (data.warning.isSuspenseDateAfterParent == true);
                        }))
                );
                break;
            case 'OperationalIcon':
                toolTip = $go(go.Panel, "Table",
