    // common styling for each indicator
    function makeIndicator(propName, label) { // the data property name
        var $go = go.GraphObject.make; // for conciseness in defining templates
        return $go(go.Shape,
            "Circle", {
                width: 12,
                height: 12,
                fill: "white",
                strokeWidth: 0,
                margin: 5
            },
            new go.Binding("fill", propName, function(t) {
                switch (t) {
                    case ("Projected on time"):
                        return node_status_ontime;
                    case ("Warning"):
                        return node_status_warning;
                    case ("Critical"):
                        return node_status_critical;
                    default:
                        return "Gray";
                }
            })
        );
    }

    function loadPage() {
        if ($scope.data.id) {
            if (diagram != undefined) {
                diagram.div = null;
                diagram = null;
            }
            var $go = go.GraphObject.make; // for conciseness in defining templates
            var node_id = "page_map";
            // STRY0072032
            if (!c.data.isSystemTreeOrientationVertical) {
                // Horizontal Settings
                diagram =
                    $go(go.Diagram, node_id, {
                        initialContentAlignment: go.Spot.Default,
                        allowZoom: true,
                        // define the layout for the diagram
                        layout: $go(go.TreeLayout, {
                            nodeSpacing: 5,
                            layerSpacing: 60
                        })
                    }, {
                        "toolManager.hoverDelay": 200
                    }, {
                        "toolManager.toolTipDuration": 10000
                    });
            } else {
                // Vertical Settings
                diagram =
                    $go(go.Diagram, node_id, {
                        initialAutoScale: go.Diagram.UniformToFill,
                        allowZoom: true,
                        // define the layout for the diagram
                        layout: $go(go.TreeLayout, {
                            angle: 90,
                            nodeSpacing: 5,
                            layerSpacing: 60
                        })
                    }, {
                        "toolManager.hoverDelay": 200
                    }, {
                        "toolManager.toolTipDuration": 10000
                    });
            }

            diagram.model = new go.TreeModel($scope.data.map);
            var fontStyle = "13px Segoe UI";

            // Define a simple node template consisting of text followed by an expand/collapse button
            // STRY0072032
            var treeOrientation;
            var treeOrientationWithinBorder;
            if (!c.data.isSystemTreeOrientationVertical) {
                treeOrientation = "Horizontal";
                treeOrientationWithinBorder = "Vertical";
            } else {
                treeOrientation = "Vertical";
                treeOrientationWithinBorder = "Horizontal";
            }
            diagram.nodeTemplate = $go(go.Node, treeOrientation, {
                    selectionAdorned: false,
                    selectionChanged: nodeSelectionChanged,
                    isTreeExpanded: true,
                    isTreeLeaf: true
                }, // this event handler is defined below
                $go(go.Panel, treeOrientationWithinBorder, // everything within the border
                    $go(go.Panel, treeOrientation, // the row of status indicators
                        makeIndicator("status", "10"),
                        $go(go.TextBlock, {
                            stretch: go.GraphObject.Horizontal,
                            //stroke: "Red",
                            textAlign: "center",
                            margin: new go.Margin(0, 5, 0, 0)

                        }),
                        $go(go.Panel, "Auto",
                            $go(go.Shape, "RoundedRectangle", {
                                    strokeWidth: 3
                                }, {
                                    fill: "Gray"
                                },
                                new go.Binding("stroke", "isSelected", function(s) {
                                    if (s)
                                        return node_selected_border;
                                    else
                                        return null;
                                }).ofObject(""),
                                new go.Binding("strokeWidth", "isSelected", function(s) {
                                    if (s)
                                        return "4";
                                    else
                                        return null;
                                }).ofObject(""),
                                new go.Binding("strokeDashArray", "isSelected", function(s) {
                                    if (s)
                                        return "dash";
                                    else
                                        return null;
                                }).ofObject(""),
                                new go.Binding("fill", "state", function(t) {
                                    return getStateColors(t, "bg");
                                })
                            ),
                            $go(go.Panel, "Vertical",
                                $go(go.Panel, "Horizontal",
                                    // removing width allows the width to be size of text.
                                    {
                                        width: 300,
                                        isOpposite: true
                                    },
                                    // STRY0109208 - Add Create Icon
                                    $go(go.TextBlock, {
                                            name: 'AddIcon',
                                            text: font_awesome_plus_o,
                                            margin: new go.Margin(2, 5, 2, 5),
                                            alignment: go.Spot.Right,
                                            font: '18px FontAwesome',
                                            editable: false,
                                            visible: true,
