                                        //the fake logic here is if level is 1 then warning color, otherwise use the default color.
                                        new go.Binding("text", "", function(data) {
                                            if (data.warning.noSuspenseDate || !data.warning.isSuspenseDateAfterChildren ||
                                                data.warning.isSuspenseDateAfterParent || data.warning.waitStatewithNoSubtasks ||
                                                data.warning.isTopSuspenseDateAfterExternalInboundDate || data.warning.isTopSuspenseDateBeforeExternalOutboundDate ||
                                                data.warning.primaryAssigneeEmpty || data.warning.assignedMemberEmpty)
                                                return font_awesome_exclamation_triangle_o;
                                            else
                                                return '';
                                        }),
                                        new go.Binding("stroke", "", function(data) {
                                            return getStateColors(data.state, "warning");
                                        }), {
                                            toolTip: toolTipJSON('ExclamationIcon')
                                        }
                                    )
                                ),
                                // end Vertical Panel
                                // ---------------------------------------------------------------------------------------
                                $go(go.TextBlock, {
                                        font: fontStyle,
                                        stroke: "white",
                                        margin: 3,
                                        text: "verticalAlignment: Center",
                                        alignment: go.Spot.Left,
                                        width: 300,
                                        wrap: go.TextBlock.WrapFit
                                    },
                                    new go.Binding("stroke", "state", function(t) {
                                        return getStateColors(t, "text");
                                    }),
                                    new go.Binding("text", "name")
                                )
                            )),
                        // this was overkill for small diagrams
                        $go("TreeExpanderButton", {
                            alignment: go.Spot.Default
                        }, {
                            visible: true
                        })
                    )
                ));


            diagram.select(diagram.findNodeForKey(display_id));
            // STRY0072032
            if (!c.data.isSystemTreeOrientationVertical) {
                diagram.initialAutoScale = go.Diagram.Uniform;
            }

            // Define a trivial link template with no arrowhead
            diagram.linkTemplate = $go(go.Link, {
                selectable: false
            }, $go(go.Shape)); // the link shape

            // Resize the graph container height when the graph changes size
            diagram.addDiagramListener('DocumentBoundsChanged', function() {
                // STRY0096156 - RJ - set Minimum Height for Tree
                var diagramHeight = parseInt(diagram.documentBounds.height > diagramMinHeight ? diagram.documentBounds.height : diagramMinHeight);
                jQuery("#" + node_id).height(diagramHeight);
            });
            // Select the node using the sys_id parameter supplied.
            //var node_select = diagram.findNodeForKey(d.sys_id);
            //diagram.select(node_select);

            // // STRY0072032 - this event handler is called when the diagram is first ready
            diagram.addDiagramListener("InitialLayoutCompleted", function(e) {
                var node = diagram.findNodeForKey(display_id);
                // and center it and select it
                // STRY0072032
                if (c.data.isSystemTreeOrientationVertical) {
                    diagram.centerRect(node.actualBounds);
                }
            });
        }
    }
};

