//                                         Changes made in CSS
// 2.7.0 | 2021-08-27 | mmcc | STRY0107400 - Draft Scheduled Tasks – UI – Publish from Subtasks
//                                         In HTML, removed unused <div id="infoBoxHolder">; added <div id="draftTaskPublishMessage">
//											to show/hide the info icon and Draft task publish message
//                                         In CSS, Removed unused #infoBoxHolder selector; added #draftTaskPublishMessage to keep
//											 a height of 30px so there is no bounce when show/hide of message;
//                                         In Server script, added data.draftTaskPublishMessage to get message for Draft task publish message;
//											added data.isTopTaskOrNotDraft = true at the top else the Draft task publish message shows before tree loads; 
//										   In Client controller, updated nodeSelectionChanged() to show a Draft publish message when 
//											Task State is Draft but not show that message for the top node.
//                                         Changes made in HTML, CSS, Server script and Client controller
// 2.7.0 | 2021-09-03 | raj   | STRY0109208 - Add Create Icon
//											Changes in Server Script and Client Script
// 2.7.0 | 2021-11-02 | mmcc | DFCT0010588 - When creating a Subtask on the Task form, record watcher shows 2 subtasks created
//											In Client controller, recordWatch() case insert, added if() .model.findNodeDataForKey() that 
//											returns null if a node with that key cannot be found; which should only add the node once
//                                          Changes in Client controller
// 2.7.0 | 2021-11-16 | raj  | DFCT0010652	"Open Task Tree View" button on Task Form opens a modal but user needs to click again to expand Task Tree View
//											Changes in Server Script, Client Controller and HTML
// 2.7.0 | 2021-11-17 | raj  | DFCT0010654 - Spelling Mistake: The "Add a Subtask" plus '+' icon in the Task/Template Information section displays the incorrect tooltip
//                                         Changes made in Server Script
//------------------------------------------------------------------------------------------------------------------------

(function() {
	// DFCT0010652
	data.hide_accordion = (input || {}).hide_accordion || (options || {}).hide_accordion || false;
	// 2.7.0 | 2021-08-27 | mmcc | STRY0107400 - Draft Scheduled Tasks – UI – Publish from Subtasks
	data.isTopTaskOrNotDraft = true;
    //data.placeholderMsg = gs.getMessage("Select Task...");
    data.loadData = false;
    data.sys_id = $sp.getParameter('sys_id');
    data.table = $sp.getParameter('table');
    data.dynamic_tree = $sp.getParameter("dynamic_tree"); // KT - TLV - STRY0057360 - Macro Widget
    if ((data.table != "x_153465_discovert_route_task_instance") || (!data.sys_id)) {
        data.id = null;
        return;
    }
    if (input) {
        data.loadData = input.loadData;
    }
    var grTask = new GlideRecordSecure('x_153465_discovert_route_task_instance');
    if (!grTask.get(data.sys_id)) {
        data.id = null;
        return;
    }
    var id = grTask.getValue("u_top_task");

    // STRY0072032
    data.isSystemTreeOrientationVertical = new tasking_System_Settings_Scripts().systemControlSetting().VerticalTree;

    var map = data.map = [];

    var grTopTask = new GlideRecordSecure('x_153465_discovert_route_task_instance');
    if (!grTopTask.get(id)) {
        data.id = null;
        return;
    }
    data.id = grTopTask.getValue('sys_id');
    data.task_tree = grTopTask.getValue('u_task_tree');

    // STRY0091260
    data.durationTitle = gs.getMessage('Tasker - Title - Duration Modal');
    data.assignmentTitle = gs.getMessage('Tasker - Title - Assignment Modal');
    data.operationalTitle = gs.getMessage('Tasker - Title - Operational Modal');
		// STRY0109208 - DFCT0010654 - Add Create Icon
		data.createTaskTitle = gs.getMessage('Add a Subtask');
    // STRY0095748
    data.durationWarningNoSuspenseDate = gs.getMessage('Tasker - Warning: Task has no Suspense Date');
    data.durationWarningInternalSuspenseDateAfterExternalDate = gs.getMessage('Tasker - Warning: Internal Suspense date is after the External Suspense Date');
    data.durationWarningInternalSuspenseBeforeExternalDate = gs.getMessage('Tasker - Warning: External Suspense Date is after Internal Suspense date for an outbound');
    data.durationWarningParent = gs.getMessage('A Subtask has a Suspense Date AFter this Task');
    data.durationWarningSubTask = gs.getMessage('Subtask Suspense Date AFTER Parent Task Suspense Date');
    data.durationWarningWaitState = gs.getMessage('Tasker - Warning: Wait state set with no subtasks');
    data.durationWarning = gs.getMessage('Tasker -  Warning Duration');
    data.assignmentWarning = gs.getMessage('Tasker -  Warning Assignment');

	// 2.7.0 | 2021-08-27 | mmcc | STRY0107400 - Draft Scheduled Tasks – UI – Publish from Subtasks
	data.draftTaskPublishMessage = gs.getMessage('Tasker - Draft task(s) can only be published from the top task.');

    // STRY0091251 - NOTE: this uses the same data building functions as the 'Tasker List Task Tree' widget id: discovertasker-recursivetasktreelist
    if (data.loadData) {
        var taskWidgetData = new TaskWidgetData();
        data.fieldsInModel = taskWidgetData.loadTaskTreeFieldsInModelAndFieldLabels(grTopTask);
        taskWidgetData.buildTaskMap('discovertasker-recursivetasktreegraph', map, grTopTask, data.fieldsInModel);
    }
    /*
    //------------------------------------------------------------------------------------------------------------------------
    var preferenceName = 'DTechApps.Tasker.TaskTreeAngle';
    var currentUser = gs.getUserID();
    var preferenceTaskTreeDirection;

    //Get the value for a specific User's User Preference
    var preference = new GlideRecordSecure('sys_user_preference');
    preference.addQuery('name', preferenceName);
    preference.addQuery('user', currentUser);
    preference.query();
    if (preference.next()) {
        preferenceTaskTreeDirection = preference.value;
    }

    if (preferenceTaskTreeDirection == '') {
        // Add User Preference
        preference = new GlideRecordSecure('sys_user_preference');
        preference.addQuery('name', preferenceName);
        preference.addQuery('user', currentUser);
        preference.query();
        if (!preference.next()) {
            preference.name = preferenceName;
            preference.value = '90';
            preference.type = 'integer';
            preference.user = currentUser;
            preference.insert(); //since you said this was a before business fule you should not need this but I wanted to give it to you just in case.
        }
    }
    //------------------------------------------------------------------------------------------------------------------------
		*/


